class Solution:
    def minimumDifference(self, nums: List[int], k: int) -> int:
        min_diff = float('inf')
        n = len(nums)
        or_set = set()

        for i in range(n):
            or_set.clear()
            current_or = 0
            for j in range(i, n):
                current_or |= nums[j]
                or_set.add(current_or)
            for val in or_set:
                min_diff = min(min_diff, abs(val - k))

        return min_diff
